When dealing with time, stick to using `std::chrono::duration` and `std::chrono::time_point`.
Just save `auto now = std::chrono::high_resolution_clock::now()` and declare `curr` when you first use it (not need to declare it here)
Later on:
```cpp
const std::chrono::milliseconds rotation_delta(10);
auto curr = std::chrono::high_resolution_clock::now();
if(curr - now > rotation_delta)
{
    //...
}
```

Nice. Looks like this will fix the behavior for `T&` in general, not just with abstract types. For example, the following test fails prior to this change:

```c++
struct MovableObject {
    bool valid = true;

    MovableObject() = default;
    MovableObject(const MovableObject &) = default;
    MovableObject &operator=(const MovableObject &) = default;
    MovableObject(MovableObject &&o) : valid(o.valid) { o.valid = false; }
    MovableObject &operator=(MovableObject &&o) { valid = o.valid; o.valid = false; return *this; }
};

py::class_<MovableObject>(m, "MovableObject");

m.def("callback_with_movable", [](std::function<void(MovableObject &)> f) {
    auto x = MovableObject();
    f(x); // lvalue reference shouldn't move out object
    return x.valid; // must still return `true`
});
```

```python
assert callback_with_movable(lambda _: None) is True  # returns `False` without `std::forward`
```

